Below is a comprehensive implementation of a Discord.js v14 bot that uses slash commands and includes a single command named `/ban`. This command allows moderators to ban users from your Discord server.

Firstly, let's install the necessary dependencies:

```bash
npm install discord.js @discordjs/builders @apisearch/sdk@^5.4.1
```

Here's the complete code for your Discord bot:

```javascript
const { SlashCommandBuilder } = require('@discordjs/builders');
const { Permissions } = require('discord.js');
const client = new discord.Client({ intents: ["Guilds", "GuildMembers", "Messages", "GuildBans", "DirectMessages", "GuildMessages"]});

client.commands = [];

if (!process.env.DISCORD_TOKEN) {
    console.error("You must set the DISCORD_TOKEN environment variable.");
    process.exit(1);
}

client.login(process.env.DISCORD_TOKEN);

client.once('ready', async () => {
    console.log('Ready!');

    // Register slash commands
    await client.application.commands.set(await client.commands.cache.registerAll(
        [
            new SlashCommandBuilder()
                .setName('ban')
                .setDescription('Bans a member from the server.')
                .addUserOption(option =>
                    option
                        .setName('user')
                        .setDescription('The user to ban.')
                        .required(true)
                )
                .addStringOption(option =>
                    option.setName('reason')
                        .setDescription('The reason for the ban.')
                        .setRequired(false)
                )
                .permissionsVerify(checkPermissions)
                .defaultPermission(false)
        ]
    ).map(command => command.toArray()));
});

client.on('interactionCreate', async interaction => {
    if (!interaction.isSlash()) return;

    const { user, options } = interaction;
    const member = await interaction.guild.members.cache.get(user.id);

    if (!interaction.guild.members.me.permissions.has(Permissions.FLAGS.BanMembers)) {
        return await interaction.reply({ content: 'I don\'t have the necessary permissions to ban members.', ephemeral: true });
    }

    const reason = options.getString('reason') ?? 'No reason provided';

    try {
        await interaction.guild.bans.create(member, { reason });
        await interaction.reply(` Successfully banned ${user} with reason: ${reason}`);
    } catch (error) {
        await interaction.reply({ content: `Failed to ban ${user}. Error: ${error}`, ephemeral: true });
    }
});

function checkPermissions(permissionCheck) {
    return permissionCheck.has(Discord.PermissionsBitField.Flags.BanMembers);
}
```

To run this bot, you'll need to replace `DISCORD_TOKEN` in your environment variables with your bot's actual token from the Discord Developer Portal.

This bot requires the `Guilds`, `GuildMembers`, `Messages`, `GuildBans`, `DirectMessages`, and `GuildMessages` intents to function correctly. You can enable these intents in the Discord Developer Portal under your bot's settings.

Also note that this bot requires moderation permissions (`BanMembers`) to function correctly. If it doesn't have these permissions, it will return an error when attempting to ban a user.

Lastly, always ensure that you keep your token secure and never share it publicly. If you accidentally expose your token, generate a new one immediately to prevent abuse of your bot.

