Cypress.Commands.add('saveScreenshot', (fileName, options = {}) => {
  const screenshotPath = Cypress.config('screenshotsFolder');
  const timestamp = new Date().getTime();
  const fileNameWithTimestamp = `${fileName}-${timestamp}.png`;
  cy.get('body').trigger('scroll').wait(100).screenshot(fileNameWithTimestamp, options);
  const screenshotFile = path.join(screenshotPath, fileNameWithTimestamp);
  // Add metadata to the file name (e.g., test title and description)
  const metadata = Cypress.env('TEST_TITLE') + '-' + Cypress.env('TEST_DESCRIPTION');
