function isPrime(n) {
  if (n <= 1) return false;
  for (let i = 2, sqrt = Math.sqrt(n); i <= sqrt; i++)
    if (n % i === 0) return false;
  return true;
}

function checkPrimeNumbersInArray(numbers) {
  if (!Array.isArray(numbers) || numbers.length !== 5)
    throw new Error("Input must be an array of exactly 5 numbers");

  numbers.forEach((num) => {
    if (isPrime(Math.abs(num))) { // Ensure negative numbers are also checked correctly
      console.log(`Found prime number: ${num}`);
    }
  });
}

// Example usage:
